if (pagina_recargada) {
	RevertirCambiosMultimedia ();
}

async function RealizarBusqueda (criterio) {
	if (criterio.trim () === '') return;
	
	// Limpiar lista de cursos
	in_busqueda.setAttribute ('data-id', '');
	lista_cursos.innerHTML = '';
	
	await fetch (
		`modulos/CursosInternos.php?busqueda=${ criterio.trim() }&no_nomina=${ no_nomina }&tipo=inst`
	)
	.then ((res) => res.json ())
	.then ((cursos) => {
		cursos.forEach ((curso) => {
			const opcion = document.createElement ('li');
			opcion.textContent = curso.Nombre;
			opcion.dataset.id =	 curso.Id_curso;
			opcion.onclick = () => {
				// Seleccionar curso
				in_busqueda.value = opcion.textContent;
				in_busqueda.setAttribute ('data-id', opcion.dataset.id);
			};
			lista_cursos.appendChild (opcion);
		});
		lista_cursos.classList.add ('habilitar');
	});
}

function BuscarCursos (campo) {
	if (!in_busqueda) {
		in_busqueda = campo;
		idle_busqueda = new IdleIn (
			in_busqueda,
			1, 500, () => RealizarBusqueda (campo.value)
		);
		in_busqueda.addEventListener (
			'input', (e) => {
				in_busqueda.dataset.id = '';
				idle_busqueda.ActualizarEspera ();
			}
		);
	}
}

function MostrarSugerencias () {
	if (!lista_cursos) 
		lista_cursos = document.querySelector ('ul.custom-datalist');

	// Ocultar lista de cursos
	if (!timer) lista_cursos.removeAttribute ('hidden');

	// Ocultar lista de cursos, una vez que el timer sea liberado
	else postTimer = () => lista_cursos.removeAttribute ('hidden');
}

function OcultarSugerencias () {
	setTimeout(() => {
		lista_cursos.classList.add ('deshabilitar');
	}, 200);
	
	if (!timer) timer = setTimeout (() => {
		lista_cursos.classList.remove ('deshabilitar');
		lista_cursos.classList.add ('habilitar');
		lista_cursos.setAttribute ('hidden', 'true');
		
		if (postTimer) {
			// Ejecutar acción pendiente
			postTimer ();
			postTimer = null;
		}
		clearTimeout (timer);
		timer = null;
	}, 500);
}

$editor.onclick = (e) => {
	if ($barra_editor) return;
	// Recuperar barra superior del editor
	$barra_editor = document.querySelector ('.barra-editor');
	$barra_nav = document.querySelector ('nav');
};

$editor.addEventListener('paste', function(event) {
	// Evitar el comportamiento predeterminado de pegado
	event.preventDefault();

	// Obtener el contenido pegado (texto plano)
	let clipboardData = event.clipboardData || window.clipboardData;
	let pastedText = clipboardData.getData('text/plain');

	// Insertar únicamente texto plano 
	document.execCommand ('insertText', false, pastedText);
});

// Agregar nuevo parrafo por defecto al presionar enter en el editor
document.execCommand ("defaultParagraphSeparator", false, "p");

function ValidarLongitudCampo (input, max) {
	const label = input.parentElement.parentElement.querySelector ('small');
	label.innerHTML = input.value.length + ' / <b>Max:</b> ' + max;
}

function RevertirCambiosMultimedia () {
	let formData = new FormData ();
	formData.append ('accion', 'limpiar_cambios');
	
	// Eliminar cambios realizados con imagenes y videos
	fetch ('modulos/util/gestion_archivos.php', {
		method: 'POST',
		body: formData
	});
	
	// Limpiar cookie de cambios
	formData = new FormData ();
	formData.append ('accion', 'aplicar_cambios');
	
	fetch ('modulos/util/gestion_archivos.php', {
		method: 'POST',
		body: 	formData
	});
}

function formatDoc (cmd, valor = null, parametro = null) {

	if (cmd === 'nota') {
		// Crear formato de nota
		const selection = window.getSelection();
		if (selection.rangeCount > 0) {
            const range = 			 	selection.getRangeAt (0);
            const selectedContent =  	range.extractContents ();
            const notaDiv = 		 	document.createElement ('div');
			const btnCerrar =		 	document.createElement ('button');

			btnCerrar.contentEditable = false;
			btnCerrar.className =		'btn-cerrar';
            notaDiv.className = 	 	'nota';
			notaDiv.style.position = 	'relative';

			btnCerrar.onclick = () => {
				btnCerrar.remove ();
				const contenidoNota = notaDiv.innerHTML;
				notaDiv.insertAdjacentHTML ('afterend', contenidoNota);
				notaDiv.remove ();
			}
			btnCerrar.setAttribute ('title', 'Remover estilo de nota');

            notaDiv.appendChild (selectedContent);
			notaDiv.appendChild (btnCerrar);
            range.insertNode 	(notaDiv);
            
            // Limpiar la selección
            selection.removeAllRanges();
        }
		return;
	}
	// Aplicar formato al texto seleccionado
	if (valor) {
		document.execCommand (cmd, false, valor); 
		return;
	}
	document.execCommand (cmd);
	if (cmd === 'removeFormat') {
		// Cambiar etiqueta a párrafo al elimnar formato
		document.execCommand ('formatBlock', false, '<p>');
	}
}

function obtenerTextoSeleccionado () {
	
	// Obtener texto seleccionado
    if (window.getSelection) {
        return window.getSelection();
    } 
	else if (document.selection) {
        return document.selection.createRange();
    } return '';
}

function AgregarElementoEditor (tipo) {
	switch (tipo) {
		case 'titulo':    CrearTitulo ();    break;
		case 'subtitulo': CrearSubtitulo (); break;
		case 'imagen': 	  CrearImagen (); 	 break;
		case 'video':	  CrearVideo (); 	 break;
	}
}

function CrearTitulo () {
	// Agregar nuevo elemento de título en el contenido del editor
	const $titulo = 		document.createElement ('h2');
	$titulo.textContent = 	"Nuevo título";
	
	CrearElementoEditor ($titulo);
}

function CrearSubtitulo () {
	// Agregar nuevo elemento de título en el contenido del editor
	const $subtitulo = 		 document.createElement ('h5');
	$subtitulo.textContent = "Nuevo subtítulo";
	
	CrearElementoEditor ($subtitulo);
}

function CrearImagen () {
	// Agregar nuevo elemento de imágen en el contenido del editor
	const $placeholder =  document.createElement ('span');
	const max_size = 	  5 * 1024; // Limitar tamaño máximo de las imágenes a 5Mb
	const input = 		  document.createElement ('input');
	const timestamp = 	  new Date().toISOString().replace(/[-:.]/g,"");
	
	input.style.display = 'none';
	input.setAttribute ('type', 'file');
	input.setAttribute ('accept', 'image/*');
	
	$placeholder.classList.add ('load-placeholder');
	$placeholder.style.opacity = 1;
	$placeholder.innerHTML = 
	'<div class="spinner-border text-danger" role="status">' +
	  '<span class="visually-hidden">Cargando...</span>' +
	'</div>' +
	'<div data-tipo="placeholder" class="my-2" contenteditable="false">' + 
		'<h5>Cargando...</h5>' + 
	'</div>';
	
	input.addEventListener ("change", (e) => {
		const archivo = 	 input.files[0];
		const tipo_archivo = archivo.type.split ('/')[0];

		if (tipo_archivo != 'image') {
			// Fue seleccionado un formato de archivo no permitido
			MostrarMensaje (
				'No se pudo cargar la imagen', 
				'El formato del archivo seleccionado no corresponde con el de una imagen.', 
				null, icono_error
			);
			return;
		}

		const url_carga = 'modulos/util/gestion_archivos.php';
		
		CrearElementoEditor ($placeholder);
		
		const cargarImagen = async () => {
			const formData = new FormData();
			formData.append ('accion', 'subir_imagen');
			formData.append ('archivo', archivo);
			formData.append ('nombre_archivo', archivo.name);
			formData.append ('timestamp', timestamp);
			
			// Subir parte del archivo
			await fetch (url_carga, {
				method: 'POST',
				body: formData
			})
			.then (async resp => {
				if (!resp.ok) return;

				// Se subió la imagen
				const archivo_cargado = await resp.text();
				const img = document.createElement ('div');
				
				img.style.display = 'flex';
				img.innerHTML = 
				'<div class="elemento-img mx-auto" draggable="false" contenteditable="false">' +
					'<button class="btn-float" onclick="EliminarComponente (this)" title="Eliminar imagen">' + 
						iconos.remover +
					'</button>' +
					'<img draggable="false" src="uploads/img/' + archivo_cargado + '" alt="" data-src="' + archivo_cargado + '" />' +
				'</div>';
				
				// Reemplazar placeholder con la imagen cargada
				$placeholder.replaceWith (img);
				img.insertAdjacentHTML ('beforebegin', '<p>&#8202;</p>');
				img.insertAdjacentHTML ('afterend', '<p>&#8202;</p>');

				// Permitir que la imagen sea alineada y reescalada
				HacerElementoAlineable 		(img.querySelector ('img'));
				HacerElementoReescalable 	(img.querySelector ('img'));
				HacerElementoProporcionable (img.querySelector ('img'));
			})
			.catch (error => {
				console.error ('Error en la solicitud', error)
			});
		};
		// Subir archivo seleccionado
		if (archivo) {
			if (Math.round (archivo.size/1024) > max_size) {
				//console.error ("El tamaño máximo permitido para los archivos de imagen es de 5 Mb.");
				MostrarMensaje (
					'No se pudo cargar la imagen', 
					'El tamaño máximo permitido para los archivos de imagen es de 5 Mb.', 
					null,
					icono_error
				);
				$placeholder.remove();
				return;
			}
			cargarImagen ();
		}
	});
	input.click();
}

function CrearVideo () {
	// Agregar nuevo elemento de video en el contenido del editor
	/* 
		Se realizará la carga al servidor utilizando el método de "chunks",
		para permitir la carga de archivos pesados.
	*/
	const $placeholder =  document.createElement ('span');
	const chunk_size = 	  5 * 1024 * 1024; // Tamaño de cada chunk: 5MB
	const input = 		  document.createElement ('input');
	const timestamp = 	  new Date().toISOString().replace(/[-:.]/g,"");

	input.name = 		  'video';
	input.style.display = 'none';
	
	input.setAttribute ('type', 'file');
	input.setAttribute ('accept', 'video/mp4, video/quicktime');
	
	$placeholder.classList.add ('load-placeholder');
	$placeholder.style.opacity = 1;
	$placeholder.innerHTML = 
	'<div class="spinner-border text-danger" role="status" readonly>' +
	  '<span class="visually-hidden" readonly>Loading...</span>' +
	'</div>' +
	'<div data-tipo="placeholder" class="my-2" contenteditable="false">' + 
		'<h5>Cargando...</h5>' + 
	'</div>';
	
	input.addEventListener ("change", (e) => {
		const archivo = 	 input.files[0];
		const total_chunks = Math.ceil (archivo.size / chunk_size);
		const url_carga = 	 'modulos/util/gestion_archivos.php';
		let chunk_actual = 	 0;

		const tipo_archivo = archivo.type;

		if (tipo_archivo != 'video/mp4' && tipo_archivo != 'video/quicktime') {
			// Fue seleccionado un formato de archivo no permitido
			MostrarMensaje (
				'No se pudo cargar el video', 
				'El formato del archivo seleccionado no corresponde con el de un MP4.', 
				null, icono_error
			); return;
		}
		
		CrearElementoEditor ($placeholder);
		
		const cargarChunk = async () => {
			const inicio = 	chunk_actual * chunk_size;
			const fin = 	Math.min (inicio + chunk_size, archivo.size);
			const chunk = 	archivo.slice (inicio, fin);
			
			const formData = new FormData();
			formData.append ('accion', 'subir_video');
			formData.append ('archivo', chunk);
			formData.append ('chunk_index', chunk_actual);
			formData.append ('total_chunks', total_chunks);
			formData.append ('nombre_archivo', archivo.name);
			formData.append ('timestamp', timestamp);
			
			// Subir parte del archivo
			await fetch (url_carga, {
				method: 'POST',
				body: formData
			})
			.then (async resp => {
				if (!resp.ok) return;
				chunk_actual++;
				$placeholder.querySelector ('h5').innerHTML = 
				'Cargando video... ' + Math.round((chunk_actual / total_chunks) * 100) + '%';

				if (chunk_actual < total_chunks) cargarChunk ();
				else {
					// Se subieron todas las partes del archivo
					const archivo_cargado = await resp.text();
					const video = document.createElement ('div');
					
					video.style.display = 'flex';

					video.innerHTML = 
					'<div class="elemento-video mx-auto" contenteditable="false">' +
						'<button class="btn-float" onclick="EliminarComponente (this)" title="Eliminar video">' + 
							'<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 384 512"><path fill="#FFF" d="M342.6 150.6c12.5-12.5 12.5-32.8 0-45.3s-32.8-12.5-45.3 0L192 210.7 86.6 105.4c-12.5-12.5-32.8-12.5-45.3 0s-12.5 32.8 0 45.3L146.7 256 41.4 361.4c-12.5 12.5-12.5 32.8 0 45.3s32.8 12.5 45.3 0L192 301.3 297.4 406.6c12.5 12.5 32.8 12.5 45.3 0s12.5-32.8 0-45.3L237.3 256 342.6 150.6z"/></svg>' +
						'</button>' +
						'<video draggable="false" controls preload="none" poster="uploads/placeholder/video.webp" data-src="' + archivo_cargado + '">' + 
							'<source src="uploads/video/' + archivo_cargado + '" type="video/mp4"></source>' +
						'</video>' +
					'</div>';
					
					// Reemplazar placeholder con el video cargado
					$placeholder.replaceWith (video);
					video.insertAdjacentHTML ('beforebegin', '<p>&#8202;</p>');
					video.insertAdjacentHTML ('afterend', '<p>&#8202;</p>');
				}
			})
			.catch (error => { console.error ('Error en la solicitud', error) });
		};
		// Subir archivo seleccionado
		if (archivo) cargarChunk ();
	});
	input.click();
}

function CambiarPosicionElemento ($elemento, posicion, icono) {
	const $contenedor_elemento = $elemento.parentElement.parentElement;

	// $elemento.classList.remove ('me-3', 'ms-3', 'mb-3');
	$contenedor_elemento.classList.remove ('me-3', 'ms-3', 'mb-3');

	switch (posicion) {
		case 'izquierda': 
			$contenedor_elemento.style.float = 'left'; 
			// $elemento.classList.add ('me-3');
			$contenedor_elemento.classList.add ('me-3');
			icono.innerHTML = iconos.desplegar + iconos.alineacion_izquierda;
			break;
		case 'centrado':  
			$contenedor_elemento.style.float = 'none'; 
			// $elemento.classList.add ('mb-2');
			$contenedor_elemento.classList.add ('mb-2');
			icono.innerHTML = iconos.desplegar + iconos.alineacion_centrada;
			break;
		case 'derecha':   
			$contenedor_elemento.style.float = 'right'; 
			// $elemento.classList.add ('ms-3');
			$contenedor_elemento.classList.add ('ms-3');
			icono.innerHTML = iconos.desplegar + iconos.alineacion_derecha;
			break;
	}
}

function CrearElementoEditor ($elemento) {
	
	// Agregar nuevo elemento al contenido del editor
	let $cursor =  obtenerTextoSeleccionado ().anchorNode;
	let posicion = null;

	// El cursor de texto no se encuentra dentro del editor o está vacío
	if ($cursor == null || !$editor.contains ($cursor) || $cursor === $editor) {
		$editor.appendChild ($elemento); 
		scrollAElemento ($elemento);
		return 'nuevo';
	}
	
	try { 
		$cursor.insertAdjacentElement ('afterend', $elemento); 
		posicion = 'insertado'; 
	} 
	catch (e) { 
		const $padre = $cursor.parentElement;
		$padre.insertAdjacentElement ('afterend', $elemento); 
		posicion = 'nuevo;'
	}
	scrollAElemento ($elemento);
	return posicion;
}

async function PrevisualizarCurso (departamento = null) {

	// No es posible generar el borrador debido a un error de validación
	if (ValidarBancoPreg ()) return null;
	if (ValidarEntradas ())  return null;
	
	// Guardar edición del curso como borrador, antes de previsualizar
	await AgregarBorradorBD (departamento)
	.then ((resolve) => {
		//alert ('Actualizado'); 
		const form = document.createElement ('form');
		form.method = 'post';
		form.action = 'visualizador.php';
		
		const input = document.createElement ('input');
		input.type = 'hidden';
		input.name = 'curso';
		input.value = JSON.stringify (curso);
		
		form.appendChild (input);
		document.body.appendChild (form);
		form.submit ();
	});
}

function ObtenerBotonesEditor () {
	return document.querySelectorAll ('.opciones-editor button:not(.inhabilitado)');
}

async function GuardarBorrador (boton, departamento = null) {
	
	// Bloquear temporalmente botón de GuardarBorrador
	boton.disabled = 		true;
	const btn_texto = 		boton.querySelector ('small');
	btn_texto.textContent = "Guardando...";
	estatus =				null;
	
	$botones = ObtenerBotonesEditor ();
	$botones.forEach (($boton) => $boton.disabled = true);
	
	await AgregarBorradorBD (departamento)
	.then((resolve) => {
		
		if (!resolve) {
			
			// Hubo un error de validación al validar los campos del editor
			btn_texto.textContent = "Verifique los campos";
			setTimeout (() => {
				$botones.forEach (($boton) => $boton.disabled = false);
				btn_texto.textContent = "Guardar";
			}, 3000); 
			estatus = 'error'; return false;
		}
		
		// Borrador guardado correctamente
		setTimeout(() => {
			btn_texto.textContent = "Borrador guardado";
			MostrarMensaje (
				"Borrador guardado",
				"Se guardó correctamente la edición del curso como borrador. " + 
				"Puedes continuar editando.",
				null, icono_success, false
			);
			estatus = 'correcto';
			$botones.forEach (($boton) => $boton.disabled = false);
		}, 1000);
		
		// Mostrar nuevamente etiqueta para guardar borrador
		setTimeout(() => {
			btn_texto.textContent = "Guardar";
		}, 3000);
	})
	.catch ((error) => {
		boton.disabled = 		false;
		btn_texto.textContent = "Guardar";
		console.error(error);
		MostrarMensaje (
			"Error",
			"No se pudo guardar el borrador debido a un error. " + 
			"Por favor, intenta más tarde."
		);
		estatus = 'error';
	}); return estatus;
}

function GenerarBorrador (departamento = null) {
	
	// No es posible generar el borrador debido a un error de validación
	if (ValidarBancoPreg ()) return null; 
	if (ValidarEntradas ()) return null;
	
	let curso = null;
	const nombre_curso = 	  document.querySelector ('input[data-tipo="in-nombre-curso"]').value;
	const descripcion_curso = document.querySelector ('#descripcion-curso').value;
	const objetivo_curso = 	  document.querySelector ('#objetivo-curso').value;
	const comentarios = 	  document.querySelector ('#comentarios-version').value;
	const curso_previo = 	  document.querySelector ('#conf-curso-modular.show #curso-previo');
	const tags =			  Array.from (document.querySelectorAll ('.tag span')).map (
								// Evitar más de dos espacios en blanco consecutivos
								(elemento) => elemento.textContent.replace (/\s{2,}/g, ' ')
							  );
	const tags_str = 		  tags.join ();

	let contenido_curso = ObtenerContenido ();
	let banco_preguntas = ObtenerBanco ();
	
	curso = {
		// Crear JSON con el contenido del curso
		nombre: 		nombre_curso,
		descripcion: 	descripcion_curso,
		objetivo:		objetivo_curso,
		comentarios: 	comentarios,
		contenido: 		contenido_curso,
		banco_preg: 	{...banco_preguntas},
		departamento: 	departamento ? departamento : 'N/A',
		tags: 			tags_str,
		curso_previo:	curso_previo ? curso_previo.dataset.id : 'NULL'
	}; 

	return curso;
}

function ObtenerContenido () {
	
	// Obtener contenido formateado en HTML del curso
	const $elemento_contenido = document.querySelector ('#contenido-curso');
	const $contenido = 			$elemento_contenido.querySelector ('.contenido-editor');
	
	const $contenido_filtrado = $contenido.cloneNode (true);
	const $botones = $contenido_filtrado.getElementsByTagName ('button');
	const $menu_opciones = $contenido_filtrado.querySelectorAll ('details');
	
	while ($botones.length > 0) {
		// Filtrar botones del contenido del curso
		$botones[0].parentNode.removeChild ($botones[0]);
	}
	// Filtrar menús de opciones (alineación)
	$menu_opciones.forEach ((elemento) => elemento.remove ());
	return $contenido_filtrado.innerHTML;
}

function ValidarEntradas () {
	
	const nombre_curso = document.querySelector ('input[data-tipo="in-nombre-curso"]');
	const descripcion =  document.querySelector ('#descripcion-curso');
	const objetivo =  	 document.querySelector ('#objetivo-curso');
	const comentarios =  document.querySelector ('#comentarios-version');
	const max_preg =	 document.querySelector ('#max-preg');
	const calif_min =	 document.querySelector ('#calif-min');
	const portada =		 document.querySelector ('#portada-curso');

	// Validar selección de curso previo únicamente si es curso modular
	const curso_previo = document.querySelector ('#conf-curso-modular.show #curso-previo');
	let id_curso_previo = null;

	if (curso_previo) {
		id_curso_previo = curso_previo.dataset.id;

		// Validar que se haya seleccionado un curso válido
		if (!id_curso_previo || id_curso_previo === '' || id_curso_previo === '-1') {
			IndicarError (curso_previo, 'No se encontró este curso');
			return true;
		}
	}

	const inputs = [
		nombre_curso, 
		descripcion, 
		objetivo, 
		comentarios, 
		max_preg, 
		calif_min, 
		portada
	];

	// Validar todos los campos del editor
	const error_validacion = ValidarMultiplesEntradas (inputs);

	if (error_validacion) {
		IndicarError (error_validacion['input'], error_validacion['error']);

		if (error_validacion.num_errores > 1) {
			MostrarIndicacionFlotante (
				'<span>Se detectaron varios <b>errores en el llenado de los campos</b> de información del curso interno.</span>',
				'<p>Recuerda que, debes llenar los campos correspodientes a:</p>' +
				'<ul>' + 
					'<li>El <a class="indicador-input" id="in-nombre-curso">nombre</a> del curso</li>' +
					'<li><a class="indicador-input" id="in-descripcion">Descripción</a> del curso</li>' +
					'<li><a class="indicador-input" id="in-comentarios">Comentarios de la versión</a></li>' +
					'<li><a class="indicador-input" id="in-max-preguntas">Cantidad de preguntas</a> por evaluación</li>' +
					'<li><a class="indicador-input" id="in-calif-min">Calificación mínima</a> aprobatoria</li>' +
				'</ul>' +
				'<p>Asegúrate de haber llenado correctamente todos los campos e inténtalo de nuevo.</p>',
				'error'
			);

			AgregarListenersErrores ([
				{input: 'in-nombre-curso', msg: 'Es necesario indicar el nombre'},
				{input: 'in-descripcion', msg: 'Es necesario proporcionar la descripción'},
				{input: 'in-comentarios', msg: ''},
				{input: 'in-max-preguntas', msg: ''},
				{input: 'in-calif-min', msg: ''}
			]);
		} return error_validacion;
	}	  return false;
}

const eliminarRecursoDelServidor = async (recurso) => {
	if (!recurso) return;

	// Eliminar recurso, en caso de que se encuentre en el servidor
	const src = 	recurso.dataset.src;
	let formData = 	new FormData ();
	
	formData.append ('accion', 'eliminar_recurso');
	formData.append ('src', src);
	
	// Eliminar recurso del servidor
	await fetch ('modulos/util/gestion_archivos.php', {
		method: 'POST',
		body: formData
	})
	.catch ((error) => console.error (error));
	
	// Limpiar cambios realizados, en las cookies
	formData = new FormData ();
	formData.append ('accion', 'eliminar_de_cookie');
	formData.append ('src', recurso.dataset.src);

	await fetch ('modulos/util/gestion_archivos.php', {
		method: 'POST',
		body: formData
	})
	.catch ((error) => console.error (error));
};

async function EliminarComponente ($boton) {

	// Eliminar componente del contenido (mediante el botón de eliminar)
	const $elemento_principal = $boton.closest ('[contenteditable="false"]');
	const recurso = $elemento_principal.classList.contains ('elemento-img') ?
					$elemento_principal.querySelector ('img') :
					$elemento_principal.querySelector ('video');

	// Comprobar si la imagen eliminada pertenece a la versión anterior de curso
	const contenido_anterior = Array.from (await ObtenerContenidoCurso (true, id_curso, id_int));
	const src_anteriores = 	   new Set (contenido_anterior.map (elemento => {
		return elemento.tagName == 'IMG' ? 
		elemento.src : elemento.querySelector ('source').src
	}));

	if (!src_anteriores.has (recurso.src)) {
		// La imagen no pertenece a la versión anterior del curso
		eliminarRecursoDelServidor (recurso);
	}
	// Remover componente
	$elemento_principal.remove ();
}

const observador = new MutationObserver ((listaMutaciones) => {
	listaMutaciones.forEach ((mutacion) => {

		// Observar cambios en el editor
		if (mutacion.type === 'childList' && mutacion.removedNodes.length > 0) {
			mutacion.removedNodes.forEach (async (nodoRemovido) => {
				if (nodoRemovido.nodeType != Node.ELEMENT_NODE) return;
				
				const elemento = nodoRemovido.querySelector ('[contenteditable="false"]');

				// Recuperar recurso multimedia eliminado
				if (elemento && elemento.dataset.tipo != "placeholder") {
					const recurso = elemento.classList.contains ('elemento-img') ?
									elemento.querySelector ('img') :
									elemento.querySelector ('video');

					if (!recurso) eliminarRecursoDelServidor (recurso);
				}
			});
		}
	});
});

// Configurar observador para el editor
observador.observe ($editor, { childList: true, subtree: false });

window.addEventListener ('beforeunload', (e) => {
	// Revertir cambios multimedia si el usuario no guarda los cambios al salir
	RevertirCambiosMultimedia ();
});